package edu.rice.comp322.streams;

import edu.rice.comp322.provided.streams.DemoApplication;
import edu.rice.comp322.provided.streams.repos.CustomerRepo;
import edu.rice.comp322.provided.streams.repos.OrderRepo;
import edu.rice.comp322.provided.streams.repos.ProductRepo;
import org.junit.jupiter.api.Assertions;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;

import javax.transaction.Transactional;
import java.util.Map;
import java.util.Set;

import static edu.rice.comp322.solutions.StreamSolutions.*;

@SpringBootTest(classes = DemoApplication.class)
public class AgentStreamSolutionsTest {

    @Autowired
    private CustomerRepo customerRepo;

    @Autowired
    private OrderRepo orderRepo;

    @Autowired
    private ProductRepo productRepo;

    @Transactional
    @Test
    public void problem6() {
        Map<String, Double> result = problemSixSeq(customerRepo, orderRepo, productRepo);
        Map<String, Double> parResult = problemSixPar(customerRepo, orderRepo, productRepo);

        Assertions.assertEquals(result.keySet(), parResult.keySet());
        for (String key : result.keySet()) {
            Assertions.assertEquals(result.get(key), parResult.get(key), 0.0001);
        }
    }

    @Transactional
    @Test
    public void problem7() {
        Map<Long, Set<Long>> result = problemSevenSeq(customerRepo, orderRepo, productRepo);
        Map<Long, Set<Long>> parResult = problemSevenPar(customerRepo, orderRepo, productRepo);
        Assertions.assertEquals(result, parResult);

        // Products 18, 20, 22 are ordered. 30 is not.
        Assertions.assertTrue(result.containsKey(18L));
        Assertions.assertTrue(result.containsKey(20L));
        Assertions.assertTrue(result.containsKey(22L));
        Assertions.assertFalse(result.containsKey(30L));

        Assertions.assertEquals(Set.of(1L, 4L, 6L, 8L, 9L), result.get(18L));
        Assertions.assertEquals(Set.of(2L, 4L, 8L), result.get(20L));
        Assertions.assertEquals(Set.of(1L, 2L, 3L, 5L, 6L, 9L), result.get(22L));
    }

    @Transactional
    @Test
    public void problem8() {
        Map<Long, Double> result = problemEightSeq(customerRepo, orderRepo, productRepo);
        Map<Long, Double> parResult = problemEightPar(customerRepo, orderRepo, productRepo);

        Assertions.assertEquals(result.keySet(), parResult.keySet());
        for (Long key : result.keySet()) {
            Assertions.assertEquals(result.get(key), parResult.get(key), 0.0001);
        }

        // Tier 0 customers: 2, 5, 8, 9, 11.
        Assertions.assertTrue(result.containsKey(2L));
        Assertions.assertTrue(result.containsKey(5L));
        Assertions.assertTrue(result.containsKey(8L));
        Assertions.assertTrue(result.containsKey(9L));
        Assertions.assertFalse(result.containsKey(11L));
    }
}

